import * as core from '@actions/core';
import * as github from '@actions/github';
import { readFile, access } from 'fs/promises';
import { constants } from 'fs';
import { LRUCache, filterRCTagsByBaseline } from './utils.js';
import * as git from './git.js';
import { SemanticVersion } from './semver.js';
import type { Commit, Tag } from './git.js';
import type { Endpoints } from '@octokit/types';

export type PullRequest =
  Endpoints['GET /repos/{owner}/{repo}/pulls/{pull_number}']['response']['data'];

type PullRequestFromCommit =
  Endpoints['GET /repos/{owner}/{repo}/commits/{commit_sha}/pulls']['response']['data'][number];

function extractPullRequestFromPayload(ev: unknown): PullRequest | undefined {
  const payload = ev as
    | { event?: { pull_request?: PullRequest }; pull_request?: PullRequest }
    | undefined;
  return payload?.event?.pull_request ?? payload?.pull_request;
}

/**
 * Return the whole Pull Request object from the Actions context when available.
 */
export function getPrFromContext(): PullRequest | undefined {
  const ctx = github.context;
  return extractPullRequestFromPayload(ctx.payload as unknown);
}

/**
 * Attempt a single lookup of the pull request associated with a commit SHA.
 * Returns undefined when the association index returns no results or on error.
 */
async function fetchPrForCommit(
  token: string,
  commitSha: string,
): Promise<PullRequest | undefined> {
  try {
    const { octokit, owner, repo } = getOctokitAndRepo(token);
    const response =
      await octokit.rest.repos.listPullRequestsAssociatedWithCommit({
        owner,
        repo,
        commit_sha: commitSha,
      });
    if (!Array.isArray(response.data) || response.data.length === 0)
      return undefined;

    const sourcePr = response.data[0] as PullRequestFromCommit;
    const prResponse = await octokit.rest.pulls.get({
      owner,
      repo,
      pull_number: sourcePr.number,
    });
    const pr = prResponse.data as PullRequest;
    core.info(`Resolved PR #${pr.number} from latest commit ${commitSha}`);
    return pr;
  } catch (err) {
    core.debug(
      `fetchPrForCommit failed for commit ${commitSha}: ${String(err)}`,
    );
    return undefined;
  }
}

/**
 * Resolve the pull request associated with the latest commit in the Actions
 * context. Retries with exponential backoff to handle GitHub's eventual
 * consistency after a squash merge.
 */
async function getPrFromLatestCommit(
  token: string,
): Promise<PullRequest | undefined> {
  if (!token) return undefined;
  const ctx = github.context;
  const commitSha = ctx.sha ?? process.env.GITHUB_SHA;
  if (!commitSha) {
    core.debug('No commit SHA available to resolve PR from latest commit');
    return undefined;
  }

  // GitHub's association index can lag after e.g. a squash merge — retry with
  // exponential backoff to handle eventual consistency.
  const retryDelaysMs = [5_000, 10_000, 20_000];

  for (let attempt = 0; attempt <= retryDelaysMs.length; attempt++) {
    const pr = await fetchPrForCommit(token, commitSha);
    if (pr) return pr;

    const delayMs = retryDelaysMs[attempt];
    if (delayMs === undefined) break;
    core.info(
      `No PRs associated with commit ${commitSha} yet (attempt ${attempt + 1}/${retryDelaysMs.length + 1}), retrying in ${delayMs / 1000}s…`,
    );
    await new Promise((resolve) => setTimeout(resolve, delayMs));
  }

  core.debug(`No PRs associated with commit ${commitSha} after all retries`);
  return undefined;
}

/**
 * Return the whole Pull Request object from the Actions context when available.
 * If the payload does not contain a PR, try resolving a PR from the latest
 * commit (push event fallback).
 */
export async function getPrFromContextOrLatestCommit(
  token: string,
): Promise<PullRequest | undefined> {
  return getPrFromContext() ?? (await getPrFromLatestCommit(token));
}

function getOctokitAndRepo(token: string) {
  const octokit = github.getOctokit(token);
  const ctx = github.context;
  const owner = ctx.repo.owner;
  const repo = ctx.repo.repo;
  return { octokit, owner, repo };
}

// Module-level cache keyed by owner/repo and operation. Tests can mock this by
// mocking the './utils' import.
const GH_CACHE = new LRUCache<Promise<unknown>>();

// Small helper to parse an Octokit commit entry into our Commit type.
function parseCommit(c: unknown): Commit {
  const cc = c as { sha?: string; commit?: { message?: string } };
  const msg = cc.commit?.message ?? '';
  const title = msg ? msg.split('\n')[0] : '';
  const body = msg ? msg.split('\n').slice(1).join('\n').trim() : undefined;
  return { sha: cc.sha!, title, body };
}

/**
 * Resolve an annotated tag (tag object) into our Tag shape.
 * Exposed for unit testing.
 */
export async function getLatestAnnotatedTag(
  token: string,
  name: string,
): Promise<Tag | undefined> {
  try {
    const { octokit, owner, repo } = getOctokitAndRepo(token);
    const ref = await octokit.rest.git.getRef({
      owner,
      repo,
      ref: `tags/${name}`,
    });
    const obj = ref.data.object as { sha: string; type?: string } | undefined;
    if (!obj || obj.type !== 'tag') return undefined;

    const tagObj = await octokit.rest.git.getTag({
      owner,
      repo,
      tag_sha: obj.sha,
    });
    const tagData = tagObj.data as {
      object?: { sha?: string };
      tagger?: { name?: string; date?: string };
      message?: string;
    };
    const commitSha = tagData.object?.sha ?? '';
    const author = tagData.tagger?.name ?? '';
    const date = tagData.tagger?.date
      ? new Date(tagData.tagger.date)
      : new Date(0);
    const content = typeof tagData.message === 'string' ? tagData.message : '';
    return { name, commit: commitSha, author, date, content } as Tag;
  } catch (e) {
    core.debug(`getLatestAnnotatedTag: failed for ${name}: ${String(e)}`);
    return undefined;
  }
}

/**
 * Resolve a lightweight tag (ref -> commit) into our Tag shape.
 * Exposed for unit testing.
 */
export async function getLatestLightweightTag(
  token: string,
  name: string,
): Promise<Tag | undefined> {
  try {
    const { octokit, owner, repo } = getOctokitAndRepo(token);
    const ref = await octokit.rest.git.getRef({
      owner,
      repo,
      ref: `tags/${name}`,
    });
    const obj = ref.data.object as { sha: string; type?: string } | undefined;
    const commitSha = obj?.sha ?? '';
    try {
      const commitRes = await octokit.rest.repos.getCommit({
        owner,
        repo,
        ref: commitSha,
      });
      const commitData = commitRes.data as {
        commit?: {
          author?: { name?: string; date?: string };
          message?: string;
        };
      };
      const author = commitData.commit?.author?.name ?? '';
      const date = commitData.commit?.author?.date
        ? new Date(commitData.commit.author.date)
        : new Date(0);
      const content = commitData.commit?.message ?? '';
      return { name, commit: commitSha, author, date, content } as Tag;
    } catch (e) {
      core.debug(
        `getLatestLightweightTag: failed to fetch commit for ${commitSha}: ${String(e)}`,
      );
      return {
        name,
        commit: commitSha,
        author: '',
        date: new Date(0),
        content: '',
      } as Tag;
    }
  } catch (e) {
    core.debug(
      `getLatestLightweightTag: failed to resolve ref for ${name}: ${String(e)}`,
    );
    return {
      name,
      commit: '',
      author: '',
      date: new Date(0),
      content: '',
    } as Tag;
  }
}

/**
 * Read a pull request title from the Actions context.
 * Checks common payload locations and returns undefined when not found.
 */
export function getPrTitleFromContext(): string | undefined {
  // Reuse getPrFromContext to avoid duplicating payload parsing logic
  const pr = getPrFromContext();
  return pr?.title;
}

/**
 * List commits for the current pull request using the Actions context.
 * First attempts to get commits from local git, then falls back to GitHub API.
 * If token is provided it will be used to construct an Octokit instance.
 */
export async function getPrCommits(token: string): Promise<Commit[]> {
  try {
    // Try to obtain a PullRequest object from context first; fall back to latest commit
    // lookup in push events and ref parsing.
    let pr = getPrFromContext();
    if (!pr && token) {
      pr = await getPrFromContextOrLatestCommit(token);
    }
    let pull_number: number | undefined = pr?.number;
    const ctx = github.context;
    if (!pull_number && ctx.ref) {
      const m = ctx.ref.match(/^refs\/pull\/(\d+)\/(?:merge|head)$/);
      if (m) pull_number = Number(m[1]);
    }

    // Try to get commits from local git first if we have PR info
    if (pr?.base?.sha && pr?.head?.sha) {
      core.debug(
        `Attempting to get PR commits from local git: ${pr.base.sha}..${pr.head.sha}`,
      );
      const localCommits = await git.getCommits(pr.base.sha, pr.head.sha);
      if (localCommits.length > 0) {
        return localCommits;
      }
    }

    // Alternative: try using branch names if available
    if (pr?.base?.ref && pr?.head?.ref) {
      core.debug(
        `Attempting to get PR commits from local git using branches: ${pr.base.ref}..${pr.head.ref}`,
      );
      const localCommits = await git.getCommits(pr.base.ref, pr.head.ref);
      if (localCommits.length > 0) {
        return localCommits;
      }
    }

    // Fallback to GitHub API
    if (!pull_number) {
      core.debug(
        'No pull request number found in context; cannot list commits',
      );
      return [];
    }
    const { octokit, owner, repo } = getOctokitAndRepo(token);
    const cacheKey = `prCommits:${owner}/${repo}:${pull_number}`;
    let p = GH_CACHE.get(cacheKey) as Promise<Commit[]> | undefined;
    if (!p) {
      let raw: Promise<Commit[]>;
      try {
        const call = octokit.rest.pulls.listCommits({
          owner,
          repo,
          pull_number,
        });
        raw = Promise.resolve(call).then((res) => {
          return res.data.map((c) => parseCommit(c));
        });
      } catch (err) {
        core.debug(
          `getPrCommits: synchronous GitHub API listCommits threw: ${String(err)}`,
        );
        return [];
      }
      const wrapped = raw.catch((err) => {
        GH_CACHE.delete(cacheKey);
        core.debug(
          `getPrCommits: GitHub API listCommits failed: ${String(err)}`,
        );
        return [] as Commit[];
      });
      p = wrapped;
      GH_CACHE.set(cacheKey, p as unknown as Promise<unknown>);
      p.finally(() => GH_CACHE.delete(cacheKey));
    }
    const commits = await p;
    core.info(`Found ${commits.length} commits in PR`);
    return commits;
  } catch (err) {
    core.debug(`getPrCommits failed: ${String(err)}`);
    return [];
  }
}

/**
 * Return the most recent tag name for the repository in the Actions context using GitHub API.
 * Returns undefined if the API call fails.
 */
export async function getLatestTag(token: string): Promise<Tag | undefined> {
  try {
    const { octokit, owner, repo } = getOctokitAndRepo(token);
    const cacheKey = `latestTag:${owner}/${repo}`;
    let p = GH_CACHE.get(cacheKey) as Promise<Tag | undefined> | undefined;
    if (!p) {
      const raw = (async (): Promise<Tag | undefined> => {
        const res = await octokit.rest.repos.listTags({
          owner,
          repo,
          per_page: 1,
        });
        const t = res.data && res.data[0] ? res.data[0] : undefined;
        if (!t || !t.name) return undefined;
        const name = t.name;

        // First try annotated tag resolution, then fallback to lightweight commit-based tag
        const annotated = await getLatestAnnotatedTag(token, name);
        if (annotated) return annotated;
        return await getLatestLightweightTag(token, name);
      })();

      const wrapped = raw.catch((err) => {
        GH_CACHE.delete(cacheKey);
        core.debug(`getLatestTag: GitHub API listTags failed: ${String(err)}`);
        return undefined;
      });
      p = wrapped;
      GH_CACHE.set(cacheKey, p as unknown as Promise<unknown>);
      p.finally(() => GH_CACHE.delete(cacheKey));
    }
    return p;
  } catch (err) {
    core.debug(`getLatestTag failed: ${String(err)}`);
    return undefined;
  }
}

// Compatibility wrapper: previously consumers used getLatestRelease which returned
// a GitHub Release-shaped object. Keep a thin shim that maps the latest tag
// into a minimal release-like shape. This can be removed after callers/tests
// are updated to use getLatestTag directly.
// getLatestRelease shim removed; callers should use getLatestTag directly.

/**
 * Downloads a file from the GitHub repository.
 * First checks if the file exists locally, then tries git, finally falls back to GitHub API.
 *
 * @param token GitHub token for API access
 * @param filePath Path to the file in the repository (e.g., 'path/to/file.md')
 * @param ref Optional git reference (commit, branch, tag) to fetch file from
 * @returns The file contents as a string, or undefined if file not found
 */
export async function getFileContent(
  token: string,
  filePath: string,
  ref?: string,
): Promise<string | undefined> {
  try {
    if (!ref) {
      try {
        await access(filePath, constants.F_OK);
        core.info(`Found file locally: ${filePath}`);
        const content = await readFile(filePath, 'utf8');
        return content;
      } catch {
        // File doesn't exist locally, continue to git method
        core.debug(`File not found locally: ${filePath}`);
      }
    }

    if (!token) {
      core.warning(
        `No token provided and file not found locally or in git: ${filePath}`,
      );
      return undefined;
    }

    core.info(
      `File not found in git, attempting to download from GitHub: ${filePath}`,
    );
    const { octokit, owner, repo } = getOctokitAndRepo(token);

    const apiParams: {
      owner: string;
      repo: string;
      path: string;
      ref?: string;
    } = {
      owner,
      repo,
      path: filePath,
    };
    if (ref) {
      apiParams.ref = ref;
    }

    const response = await octokit.rest.repos.getContent(apiParams);

    // GitHub API returns base64 encoded content for files
    if (
      'content' in response.data &&
      typeof response.data.content === 'string'
    ) {
      const content = Buffer.from(response.data.content, 'base64').toString(
        'utf8',
      );
      core.info(`Successfully downloaded file from GitHub: ${filePath}`);
      return content;
    } else {
      core.warning(
        `File ${filePath} is not a regular file or content not available`,
      );
      return undefined;
    }
  } catch (err) {
    core.warning(`Failed to get file content for ${filePath}: ${String(err)}`);
    return undefined;
  }
}

/**
 * Get all RC (Release Candidate) tags since a baseline version using GitHub API.
 * This function fetches RC tags from GitHub repository tags only.
 */
export async function getReleaseCandidates(
  token: string,
  baseline: SemanticVersion,
): Promise<Array<{ name: string }>> {
  try {
    if (!token) {
      core.debug('No token provided for GitHub API');
      return [];
    }

    const ctx = github.context;
    const owner = ctx.repo.owner;
    const repo = ctx.repo.repo;
    const octokit = github.getOctokit(token);

    // Fetch only repository tags (not releases)
    const per_page = 100;
    const allTags: Array<{ name: string }> = [];

    // Fetch tag names (paged)
    let page = 1;
    while (true) {
      const res = await octokit.rest.repos.listTags({
        owner,
        repo,
        per_page,
        page,
      });
      if (!res || !Array.isArray(res.data) || res.data.length === 0) break;
      for (const t of res.data) {
        if (t.name) {
          allTags.push({ name: t.name });
        }
      }
      if (res.data.length < per_page) break;
      page += 1;
    }

    // Use shared filtering logic
    const results = filterRCTagsByBaseline(allTags, baseline);

    core.info(
      `Found ${results.length} release-candidate tag(s) from GitHub API since latest release`,
    );
    return results;
  } catch (err) {
    core.debug(`getReleaseCandidatesSinceLatestRelease failed: ${String(err)}`);
    return [];
  }
}

/**
 * Ensure that all impact labels exist on the repository.
 * Creates any missing labels with appropriate colors.
 *
 * @param token GitHub token for API access
 * @param labelPrefix Optional prefix for label names (e.g., "semVersie:")
 */
export async function ensureImpactLabels(
  token: string,
  labelPrefix: string = '',
): Promise<void> {
  try {
    const { octokit, owner, repo } = getOctokitAndRepo(token);

    // Define the impact labels with colors
    const impactLabels = [
      {
        name: 'noimpact',
        color: '8b949e',
        description: 'No version bump needed',
      },
      {
        name: 'patch',
        color: '0e8a16',
        description: 'Patch version bump (bug fixes)',
      },
      {
        name: 'minor',
        color: '1d76db',
        description: 'Minor version bump (new features)',
      },
      {
        name: 'major',
        color: 'd93f0b',
        description: 'Major version bump (breaking changes)',
      },
    ];

    // Get existing labels
    const existingLabels = await octokit.rest.issues.listLabelsForRepo({
      owner,
      repo,
    });
    const existingLabelNames = new Set(
      existingLabels.data.map((label) => label.name),
    );

    // Create missing labels
    for (const label of impactLabels) {
      const fullLabelName = labelPrefix
        ? `${labelPrefix}${label.name}`
        : label.name;

      if (!existingLabelNames.has(fullLabelName)) {
        core.info(`Creating label: ${fullLabelName}`);
        await octokit.rest.issues.createLabel({
          owner,
          repo,
          name: fullLabelName,
          color: label.color,
          description: label.description,
        });
      } else {
        core.debug(`Label already exists: ${fullLabelName}`);
      }
    }
  } catch (err) {
    core.warning(`Failed to ensure impact labels: ${String(err)}`);
  }
}

/**
 * Add an impact label to a pull request.
 *
 * @param token GitHub token for API access
 * @param prNumber Pull request number
 * @param impactName The impact name (e.g., 'patch', 'minor', 'major')
 * @param labelPrefix Optional prefix for the label name
 */
export async function addImpactLabelToPr(
  token: string,
  prNumber: number,
  impactName: string,
  labelPrefix: string = '',
): Promise<void> {
  try {
    const { octokit, owner, repo } = getOctokitAndRepo(token);
    const fullLabelName = labelPrefix
      ? `${labelPrefix}${impactName}`
      : impactName;

    core.info(`Adding label '${fullLabelName}' to PR #${prNumber}`);
    await octokit.rest.issues.addLabels({
      owner,
      repo,
      issue_number: prNumber,
      labels: [fullLabelName],
    });
  } catch (err) {
    core.warning(`Failed to add label to PR #${prNumber}: ${String(err)}`);
  }
}
